<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='Results';
function gradeFromPct(float $p): string {return $p>=90?'A+':($p>=80?'A':($p>=70?'B':($p>=60?'C':'D')));} 
if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf();$marks=(float)post('marks','0');$pct=$marks; $grade=gradeFromPct($pct); $gpa=round($pct/10,2); $cgpa=$gpa; executeSql('INSERT INTO results(exam_id,student_id,marks,percentage,grade,gpa,cgpa) VALUES (?,?,?,?,?,?,?) ON DUPLICATE KEY UPDATE marks=VALUES(marks),percentage=VALUES(percentage),grade=VALUES(grade),gpa=VALUES(gpa),cgpa=VALUES(cgpa)',[(int)post('exam_id'),(int)post('student_id'),$marks,$pct,$grade,$gpa,$cgpa]); header('Location: index.php'); exit;}
$ex=fetchAll('SELECT id,exam_name FROM exams ORDER BY id DESC'); $st=fetchAll('SELECT id,full_name FROM students ORDER BY full_name'); $rows=fetchAll('SELECT r.*,e.exam_name,s.full_name FROM results r JOIN exams e ON e.id=r.exam_id JOIN students s ON s.id=r.student_id ORDER BY r.id DESC'); include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><form method="post" class="row g-2"><?=csrfField()?><div class="col"><select name="exam_id" class="form-select"><?php foreach($ex as $e):?><option value="<?=$e['id']?>"><?=e($e['exam_name'])?></option><?php endforeach;?></select></div><div class="col"><select name="student_id" class="form-select"><?php foreach($st as $s):?><option value="<?=$s['id']?>"><?=e($s['full_name'])?></option><?php endforeach;?></select></div><div class="col"><input type="number" step="0.01" name="marks" class="form-control" placeholder="Marks /100"></div><div class="col"><button class="btn btn-primary">Save Result</button></div></form><hr><table class="table"><tr><th>Exam</th><th>Student</th><th>%</th><th>Grade</th><th>CGPA</th><th></th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['exam_name'])?></td><td><?=e($r['full_name'])?></td><td><?=$r['percentage']?></td><td><?=$r['grade']?></td><td><?=$r['cgpa']?></td><td><a target="_blank" href="marksheet.php?id=<?=$r['id']?>">Marksheet</a></td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
